function [nmbImg,imgLst] = fFileLstV01(inpDir,fName,fKind)%% Function to get a list of existing file and shot number, ver.1%% [nmbImg,imgLst] = fImgLstV01(inpDir,fName,fKind)%% inpDir: directory to look for images% fName: part of the name of the images, like 'OTR'% fKind: like 'png' or 'txt'%% nmbImg: number of image exist% imgLst: list of the name of images%% Kei Nakamura% Created on Friday, August 14th 2009.% Modified on Friday, June 11th 2010.%%imgLst = dir([inpDir,'/Scan*',fName,'*.',fKind]);  % image listbgLst = dir([inpDir,'/Scan*',fName,'BG*.',fKind]);  % image listif numel(bgLst)>0    bgL = numel(bgLst(1).name); % length of bg nameelse    bgL = 0;endnameL = zeros(numel(imgLst),1);   % allocationfor ii=1:numel(imgLst);    nameL(ii) = numel(imgLst(ii).name); % name lengthendk = find(nameL~=bgL);   imgLst = imgLst(k); % select non-background imagenmbImg = numel(imgLst);
